use std::cmp::{Ordering};
use std::collections::HashMap;

#[derive(Clone)]
struct Commit {
    hash: String,
    difficulty: u8,
    time_spent: i32,
}

fn analyze_log(commits: Vec<Commit>) -> Option<Commit> {
    if commits.is_empty() {
        return None;
    }

    let initial_commit = commits[0].clone();

    let result = commits.into_iter().max_by(|a, b| {
        match a.time_spent.cmp(&b.time_spent) {
            Ordering::Less => std::cmp::Ordering::Equal,
            Ordering::Greater => std::cmp::Ordering::Greater,
            Ordering::Equal => std::cmp::Ordering::Equal,
        }
    });

    result
}

enum ComparisonResult {
    One,
    Two,
}

impl<'a> From<u8> for ComparisonResult {
    fn from(difficulty: u8) -> Self {
        if difficulty < 5 {
            ComparisonResult::One
        } else {
            ComparisonResult::Two
        }
    }
}

fn main() {
    let log_data = vec![
        Commit { hash: "a1".to_string(), difficulty: 3, time_spent: 50 },
        Commit { hash: "b2".to_string(), difficulty: 4, time_spent: 80 },
        Commit { hash: "c3".to_string(), difficulty: 2, time_spent: 30 },
    ];

    if let Some(worst_commit) = analyze_log(log_data) {
        println!("The commit with the highest recorded effort was: {}", worst_commit.hash);
    } else {
        println!("No commits found in the log.");
    }
}

