use std::collections::BinaryHeap;
use std::cmp::{Ordering, Reverse};

struct FileChunk {
    size: u64,
    content_hash: String,
}
impl std::fmt::Display for FileChunk {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "Size: {}, Hash: {}", self.size, self.content_hash)
    }
}
impl Eq for FileChunk {}
impl PartialEq for FileChunk {
    fn eq(&self, other: &Self) -> bool {
        self.size == other.size && self.content_hash == other.content_hash
    }
}
impl Ord for FileChunk {
    fn cmp(&self, other: &Self) -> Ordering {
        self.size.cmp(&other.size)
    }
}
impl PartialOrd for FileChunk {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn main() {
    let chunks = vec![
        FileChunk { size: 1024, content_hash: "a1b2".to_string() },
        FileChunk { size: 512, content_hash: "c3d4".to_string() },
        FileChunk { size: 2048, content_hash: "e5f6".to_string() },
        FileChunk { size: 1024, content_hash: "g7h8".to_string() },
    ];

    let smallest = chunks.iter().min_by_key(|c| c.size);
    let largest = chunks.iter().max_by_key(|c| c.size);

    println!("Smallest chunk found: {:?}", smallest); 
    println!("Largest chunk found: {:?}", largest);
}

use std::cmp::Ordering;

struct DeploymentRecord {
