    status: String,
    timestamp: i64,
    severity_score: u32,
}

fn main() {
    let records = vec![
        DeploymentRecord { name: "auth-svc".to_string(), status: "Failed".to_string(), timestamp: 1678886400, severity_score: 5 },
        DeploymentRecord { name: "api-gateway".to_string(), status: "Success".to_string(), timestamp: 1678887200, severity_score: 1 },
        DeploymentRecord { name: "db-migrator".to_string(), status: "Failed".to_string(), timestamp: 1678885900, severity_score: 10 },
        DeploymentRecord { name: "auth-svc".to_string(), status: "Success".to_string(), timestamp: 1678888000, severity_score: 2 },
    ];

    let worst_record = records.iter().max_by_key(|r| (r.severity_score, r.timestamp));

