use std::cmp::Ordering;

struct Endpoint {
    name: String,
    priority_score: i32,
}

fn main() {
    let endpoints = vec![
        Endpoint {
            name: "auth-service".to_string(),
            priority_score: 15,
        },
        Endpoint {
            name: "user-profile".to_string(),
            priority_score: 22,
        },
        Endpoint {
            name: "rate-limiter".to_string(),
            priority_score: 8,
        },
        Endpoint {
            name: "metrics-aggregator".to_string(),
            priority_score: 19,
        },
    ];

    let best_endpoint = endpoints.iter().max_by_key(|e| e.priority_score);

    match best_endpoint {
        Some(endpoint) => {
            println!("The highest priority endpoint is: {}", &endpoint.name);
            println!("With a score of: {}", endpoint.priority_score);
        }
        None => {
            println!("No endpoints provided.");
